// TestReadinessDiscountsStalExternalBlockerWithUnblockedNote verifies that
// when a bead has an older external-blocker event but a newer operator note
// explicitly says the blocker was cleared, readiness does not treat it as
// currently blocked and instead classifies the bead as ready.
func TestReadinessDiscountsStalExternalBlockerWithUnblockedNote(t *testing.T) {
	root := newPreClaimIntakeHookTestRoot(t)
	inner, beadRef := newPreClaimIntakeHookTestStore(t, root)
	store := &parkCountingStore{claimCountingStore: &claimCountingStore{Store: inner}}

	// Add an older event indicating a blocker was encountered.
	blockerEventBody, err := json.Marshal(map[string]any{
		"reason":  "hidden_external_blocker",
		"detail":  "Redpanda fails to start due to AIO slot exhaustion on WSL2",
		"blocked": true,
	})
	require.NoError(t, err)
	require.NoError(t, inner.AppendEvent(beadRef.ID, bead.BeadEvent{
		Kind:      "execute-bead",
		Summary:   "no_changes_blocked",
		Body:      string(blockerEventBody),
		Actor:     "agent",
		Source:    "test-agent-run-1",
		CreatedAt: time.Now().UTC().Add(-24 * time.Hour), // 24 hours ago
	}))

	// Now add a newer note saying the blocker was cleared.
	require.NoError(t, inner.Update(beadRef.ID, func(b *bead.Bead) {
		b.Notes = "Unblocked 2026-05-21: the prior Redpanda/AIO blocker was stale after commit 90cd8348 bounded Redpanda test storage with an owned tmpfs mount. The container became ready and was cleaned up."
	}))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-stale-blocker",
				ResultRev: "stale-blocker",
			}, nil
		}),
	}

	// The readiness assessment should respect the operator note and classify
	// the bead as ready, not as blocked or operator_required.
	svc := &preClaimIntakeHookServiceStub{
		finalText: `{"classification":"ready","tractability":"tractable","score":0,"rationale":"bead is atomic and ready; prior blocker was cleared per notes","readiness_checks":[]}`,
	}
	intakeHook := NewPreClaimIntakeHook(root, store, intakeHookTestConfig(), svc, nil)

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:               true,
		PreClaimIntakeHook: intakeHook,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// The bead should be claimed and executed (not parked).
	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "readiness with unblocked note must claim")
	assert.Equal(t, int32(0), atomic.LoadInt32(&store.parkCalls), "readiness with unblocked note must not park for stale blocker")
	assert.Equal(t, int32(1), atomic.LoadInt32(&svc.executeCalls), "readiness hook must execute once")
	assert.Equal(t, 1, result.Successes)
	assert.Equal(t, 1, result.Attempts)

	got, err := inner.Get(beadRef.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status)
	assert.Contains(t, got.Notes, "Unblocked 2026-05-21")

	// Verify the hook received the notes in the prompt.
	assert.Contains(t, svc.lastReq.Prompt, "Unblocked 2026-05-21")
}
